### Gas 最佳化模式

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title GasOptimizationPatterns
/// @notice Gas 消耗最小化的參考模式
contract GasOptimizationPatterns {
    // 模式 1：儲存打包——把多個值塞進一個 32 位元組的槽
    // 差：3 個槽（96 位元組）
    // uint256 id;      // 槽 0
    // uint256 amount;  // 槽 1
    // address owner;   // 槽 2

    // 好：2 個槽（64 位元組）
    struct PackedData {
        uint128 id;       // 槽 0（16 位元組）
        uint128 amount;   // 槽 0（16 位元組）——同一個槽！
        address owner;    // 槽 1（20 位元組）
        uint96 timestamp; // 槽 1（12 位元組）——同一個槽！
    }

    // 模式 2：自定義 error 比 require 字串每次 revert 省約 50 Gas
    error Unauthorized(address caller);
    error InsufficientBalance(uint256 requested, uint256 available);

    // 模式 3：查詢用 mapping 不用陣列——O(1) vs O(n)
    mapping(address => uint256) public balances;

    // 模式 4：把儲存讀取快取到記憶體
    function optimizedTransfer(address to, uint256 amount) external {
        uint256 senderBalance = balances[msg.sender]; // 1 次 SLOAD
        if (senderBalance < amount) {
            revert InsufficientBalance(amount, senderBalance);
        }
        unchecked {
            // 上面已經檢查過，這裡是安全的
            balances[msg.sender] = senderBalance - amount;
        }
        balances[to] += amount;
    }

    // 模式 5：外部只讀陣列引數用 calldata
    function processIds(uint256[] calldata ids) external pure returns (uint256 sum) {
        uint256 len = ids.length; // 快取長度
        for (uint256 i; i < len;) {
            sum += ids[i];
            unchecked { ++i; } // 省 Gas——不可能溢位
        }
    }

    // 模式 6：優先用 uint256 / int256——EVM 按 32 位元組字操作
    // 更小的型別（uint8、uint16）需要額外的掩碼操作，除非在儲存中打包
}
