### 程式碼示例：符號學與語言審計

```typescript
// CQ 策略師：審計 UI 資料中的文化摩擦
export function auditWorkflowForExclusion(uiComponent: UIComponent) {
  const auditReport = [];

  // 示例：姓名校驗檢查
  if (uiComponent.requires('firstName') && uiComponent.requires('lastName')) {
      auditReport.push({
          severity: 'HIGH',
          issue: '僵化的西方姓名規範',
          fix: '合併為單一的"全名"或"常用名"欄位。許多文化不使用嚴格的名/姓劃分，可能使用多個姓氏，或將家族姓放在前面。'
      });
  }

  // 示例：色彩符號學檢查
  if (uiComponent.theme.errorColor === '#FF0000' && uiComponent.targetMarket.includes('APAC')) {
      auditReport.push({
          severity: 'MEDIUM',
          issue: '色彩符號衝突',
          fix: '在中國金融語境中，紅色代表正增長。確保 UX 透過文字/圖示明確標註錯誤狀態，而非僅依賴紅色。'
      });
  }

  // 示例：日期格式檢查
  if (uiComponent.dateFormat === 'MM/DD/YYYY') {
      auditReport.push({
          severity: 'MEDIUM',
          issue: '硬編碼美式日期格式',
          fix: '使用 Intl.DateTimeFormat 根據使用者 locale 自動格式化。全球大多數地區使用 DD/MM/YYYY 或 YYYY-MM-DD。'
      });
  }

  // 示例：性別選項檢查
  if (uiComponent.genderOptions?.length === 2) {
      auditReport.push({
          severity: 'HIGH',
          issue: '二元性別限制',
          fix: '至少提供：男性、女性、非二元、自定義填寫、不願透露。部分地區法律要求更多選項。'
      });
  }

  return auditReport;
}
```

### 程式碼示例：國際化架構檢查

```typescript
// 檢測 i18n 硬編碼問題
export function auditI18nReadiness(codebase: CodeFile[]) {
  const issues = [];

  for (const file of codebase) {
    // 硬編碼貨幣符號
    if (file.content.match(/['"]\$[\d,.]+['"]/)) {
      issues.push({
        file: file.path,
        severity: 'HIGH',
        issue: '硬編碼美元符號',
        fix: '使用 Intl.NumberFormat(locale, { style: "currency", currency }) 處理貨幣顯示'
      });
    }

    // 硬編碼排序（不適用於所有語言）
    if (file.content.match(/\.sort\(\)/) && !file.content.includes('localeCompare')) {
      issues.push({
        file: file.path,
        severity: 'MEDIUM',
        issue: '預設排序不適用於非拉丁字母',
        fix: '使用 Intl.Collator 或 String.prototype.localeCompare() 進行語言感知排序'
      });
    }
  }

  return issues;
}
```

## 全球化審計清單

| 維度 | 檢查項 | 常見問題 |
|------|--------|----------|
| 姓名 | 是否支援單名、多姓、長名 | 冰島人沒有姓氏，印尼人常用單名 |
| 地址 | 是否有非美式地址支援 | 日本地址從大到小，巴西有 complemento |
| 電話 | 是否支援國際格式 | 不同國家號碼長度不同（中國 11 位，美國 10 位） |
| 日期 | 是否用 locale 格式化 | 2/3/2024 在美國是 2 月，在英國是 3 月 |
| 貨幣 | 是否支援多幣種顯示 | 日元沒有小數點，印度用 lakh 分隔 |
| 文字方向 | 是否支援 RTL | 阿拉伯語、希伯來語需要映象整個 UI |
| 文字長度 | UI 是否適應翻譯後的文字膨脹 | 德語翻譯通常比英語長 30-40% |
| 日曆 | 是否支援非公曆 | 伊朗用波斯歷，泰國用佛曆 |

