    subject: z.string().min(5).max(200).describe("工單標題，5-200 字"),
    priority: z.enum(["low", "medium", "high", "urgent"])
      .describe("優先順序：low=一般諮詢, medium=功能問題, high=影響業務, urgent=系統不可用"),
    description: z.string().describe("問題詳細描述"),
  },
  async ({ customer_id, subject, priority, description }) => {
    // 先驗證客戶存在
    const customer = await db.customers.findById(customer_id);
    if (!customer) {
      return {
        content: [{
          type: "text",
          text: `客戶 ID "${customer_id}" 不存在。` +
                `請先用 search_customers 工具查詢正確的客戶 ID。`,
        }],
        isError: true,
      };
    }

    const ticket = await db.tickets.create({
      customerId: customer_id,
      subject,
      priority,
      description,
      status: "open",
      createdAt: new Date().toISOString(),
    });

    return {
      content: [{
        type: "text",
        text: JSON.stringify({
          ticket_id: ticket.id,
          status: "open",
          message: `工單已建立，編號 ${ticket.id}，已分配給 ${customer.region} 區域的值班工程師。`,
        }, null, 2),
      }],
    };
  }
);

