### Python MCP 伺服器

```python
from mcp.server import Server
from mcp.types import Tool, TextContent
from pydantic import BaseModel, Field
import json

app = Server("analytics-server")


class QueryParams(BaseModel):
    sql: str = Field(description="只讀 SQL 查詢，禁止 INSERT/UPDATE/DELETE")
    timeout_seconds: int = Field(default=30, ge=1, le=120,
                                  description="查詢超時秒數")


@app.tool("run_analytics_query")
async def run_query(params: QueryParams) -> list[TextContent]:
    """
    在只讀副本上執行分析查詢。
    僅支援 SELECT 語句。結果限制在 1000 行以內。
    """
    sql_upper = params.sql.strip().upper()

    # 安全檢查：只允許 SELECT
    if not sql_upper.startswith("SELECT"):
        return [TextContent(
            type="text",
            text="錯誤：只允許 SELECT 查詢。"
                 "如需修改資料，請使用對應的業務工具。"
        )]

    # 禁止危險關鍵字
    dangerous = ["DROP", "DELETE", "UPDATE", "INSERT", "ALTER", "TRUNCATE"]
    for keyword in dangerous:
        if keyword in sql_upper:
            return [TextContent(
                type="text",
                text=f"錯誤：查詢中包含禁止關鍵字 {keyword}。"
                     f"此工具僅支援只讀查詢。"
            )]

    try:
        rows = await db.execute_readonly(
            params.sql,
            timeout=params.timeout_seconds,
            row_limit=1000,
        )
        return [TextContent(
            type="text",
            text=json.dumps({
                "row_count": len(rows),
                "rows": rows[:100],  # 返回前 100 行
                "truncated": len(rows) > 100,
                "total_available": len(rows),
            }, ensure_ascii=False, indent=2)
        )]
    except TimeoutError:
        return [TextContent(
            type="text",
            text=f"查詢在 {params.timeout_seconds}s 內未完成。"
                 f"建議：新增 WHERE 條件或 LIMIT 子句縮小範圍。"
        )]
```

